import{_ as e}from"./plugin-vue_export-helper.21dcd24c.js";import{d as p}from"./app.30963f6b.js";const n={},i=p('<h1 id="nginx-\u9AD8\u6027\u80FD\u7684web\u670D\u52A1\u5668" tabindex="-1"><a class="header-anchor" href="#nginx-\u9AD8\u6027\u80FD\u7684web\u670D\u52A1\u5668" aria-hidden="true">#</a> Nginx\uFF1A\u9AD8\u6027\u80FD\u7684Web\u670D\u52A1\u5668</h1><p>Web \u670D\u52A1\u5668\u5C31\u90A3\u4E48\u51E0\u6B3E\uFF0C\u76EE\u524D\u5E02\u9762\u4E0A\u4E3B\u6D41\u7684\u53EA\u6709\u4E24\u4E2A\uFF1AApache \u548C Nginx\uFF0C\u4E24\u8005\u5408\u8BA1\u5360\u636E\u4E86\u8FD1 90% \u7684\u5E02\u573A\u4EFD\u989D\u3002</p><p>\u4ECA\u5929\u6211\u8981\u8BF4\u7684\u5C31\u662F\u5176\u4E2D\u7684 Nginx\uFF0C\u5B83\u662F Web \u670D\u52A1\u5668\u7684\u201C\u540E\u8D77\u4E4B\u79C0\u201D\uFF0C\u867D\u7136\u6BD4 Apache \u5C0F\u4E86 10 \u5C81\uFF0C\u4F46\u589E\u957F\u901F\u5EA6\u5341\u5206\u8FC5\u731B\uFF0C\u5DF2\u7ECF\u8FBE\u5230\u4E86\u4E0E Apache\u201C\u5E73\u8D77\u5E73\u5750\u201D\u7684\u5730\u4F4D\uFF0C\u800C\u5728\u201CTop Million\u201D\u7F51\u7AD9\u4E2D\u66F4\u662F\u8D85\u8FC7\u4E86 Apache\uFF0C\u62E5\u6709\u8D85\u8FC7 50% \u7684\u7528\u6237\u3002</p><p>\u5728\u8FD9\u91CC\u5FC5\u987B\u8981\u8BF4\u4E00\u4E0B Nginx \u7684\u6B63\u786E\u53D1\u97F3\uFF0C\u5B83\u5E94\u8BE5\u8BFB\u6210\u201CEngine X\u201D\uFF0C\u4F46\u6211\u4E2A\u4EBA\u611F\u89C9\u201CX\u201D\u5FF5\u8D77\u6765\u592A\u201C\u62D7\u53E3\u201D\uFF0C\u8FD8\u662F\u6BD4\u8F83\u503E\u5411\u4E8E\u8BFB\u505A\u201CEngine ks\u201D\uFF0C\u8FD9\u4E5F\u4E0E UNIX\u3001Linux \u7684\u53D1\u97F3\u4E00\u81F4\u3002</p><h2 id="\u8FDB\u7A0B\u6C60" tabindex="-1"><a class="header-anchor" href="#\u8FDB\u7A0B\u6C60" aria-hidden="true">#</a> \u8FDB\u7A0B\u6C60</h2><p>Nginx \u662F\u4E2A\u201C\u8F7B\u91CF\u7EA7\u201D\u7684 Web \u670D\u52A1\u5668\uFF0C\u201C\u8F7B\u91CF\u7EA7\u201D\u662F\u76F8\u5BF9\u4E8E\u201C\u91CD\u91CF\u7EA7\u201D\u800C\u8A00\u7684\u3002\u201C\u91CD\u91CF\u7EA7\u201D\u5C31\u662F\u6307\u670D\u52A1\u5668\u8FDB\u7A0B\u5F88\u201C\u91CD\u201D\uFF0C\u5360\u7528\u5F88\u591A\u8D44\u6E90\uFF0C\u5F53\u5904\u7406 HTTP \u8BF7\u6C42\u65F6\u4F1A\u6D88\u8017\u5927\u91CF\u7684 CPU \u548C\u5185\u5B58\uFF0C\u53D7\u5230\u8FD9\u4E9B\u8D44\u6E90\u7684\u9650\u5236\u5F88\u96BE\u63D0\u9AD8\u6027\u80FD\u3002\u800C Nginx \u4F5C\u4E3A\u201C\u8F7B\u91CF\u7EA7\u201D\u7684\u670D\u52A1\u5668\uFF0C\u5B83\u7684 CPU\u3001\u5185\u5B58\u5360\u7528\u90FD\u975E\u5E38\u5C11\uFF0C\u540C\u6837\u7684\u8D44\u6E90\u914D\u7F6E\u4E0B\u5C31\u80FD\u591F\u4E3A\u66F4\u591A\u7684\u7528\u6237\u63D0\u4F9B\u670D\u52A1\uFF0C\u5176\u5965\u79D8\u5728\u4E8E\u5B83\u72EC\u7279\u7684\u5DE5\u4F5C\u6A21\u5F0F\u3002</p><p><img src="https://mc-web-1259409954.cos.ap-guangzhou.myqcloud.com/MyImages/202205142025088.png" alt="img"></p><p>\u5728 Nginx \u4E4B\u524D\uFF0CWeb \u670D\u52A1\u5668\u7684\u5DE5\u4F5C\u6A21\u5F0F\u5927\u591A\u662F\u201CPer-Process\u201D\u6216\u8005\u201CPer-Thread\u201D\uFF0C\u5BF9\u6BCF\u4E00\u4E2A\u8BF7\u6C42\u4F7F\u7528\u5355\u72EC\u7684\u8FDB\u7A0B\u6216\u8005\u7EBF\u7A0B\u5904\u7406\u3002\u8FD9\u5C31\u5B58\u5728\u521B\u5EFA\u8FDB\u7A0B\u6216\u7EBF\u7A0B\u7684\u6210\u672C\uFF0C\u8FD8\u4F1A\u6709\u8FDB\u7A0B\u3001\u7EBF\u7A0B\u201C\u4E0A\u4E0B\u6587\u5207\u6362\u201D\u7684\u989D\u5916\u5F00\u9500\u3002\u5982\u679C\u8BF7\u6C42\u6570\u91CF\u5F88\u591A\uFF0CCPU \u5C31\u4F1A\u5728\u591A\u4E2A\u8FDB\u7A0B\u3001\u7EBF\u7A0B\u4E4B\u95F4\u5207\u6362\u65F6\u201C\u75B2\u4E8E\u5954\u547D\u201D\uFF0C\u5E73\u767D\u5730\u6D6A\u8D39\u4E86\u8BA1\u7B97\u65F6\u95F4\u3002</p><p>Nginx \u5219\u5B8C\u5168\u4E0D\u540C\uFF0C\u201C\u4E00\u53CD\u60EF\u4F8B\u201D\u5730\u6CA1\u6709\u4F7F\u7528\u591A\u7EBF\u7A0B\uFF0C\u800C\u662F\u4F7F\u7528\u4E86\u201C<strong>\u8FDB\u7A0B\u6C60 + \u5355\u7EBF\u7A0B</strong>\u201D\u7684\u5DE5\u4F5C\u6A21\u5F0F\u3002</p><p><strong>Nginx \u5728\u542F\u52A8\u7684\u65F6\u5019\u4F1A\u9884\u5148\u521B\u5EFA\u597D\u56FA\u5B9A\u6570\u91CF\u7684 worker \u8FDB\u7A0B\uFF0C\u5728\u4E4B\u540E\u7684\u8FD0\u884C\u8FC7\u7A0B\u4E2D\u4E0D\u4F1A\u518D fork \u51FA\u65B0\u8FDB\u7A0B\uFF0C\u8FD9\u5C31\u662F\u8FDB\u7A0B\u6C60\uFF0C\u800C\u4E14\u53EF\u4EE5\u81EA\u52A8\u628A\u8FDB\u7A0B\u201C\u7ED1\u5B9A\u201D\u5230\u72EC\u7ACB\u7684 CPU \u4E0A\uFF0C\u8FD9\u6837\u5C31\u5B8C\u5168\u6D88\u9664\u4E86\u8FDB\u7A0B\u521B\u5EFA\u548C\u5207\u6362\u7684\u6210\u672C\uFF0C\u80FD\u591F\u5145\u5206\u5229\u7528\u591A\u6838 CPU \u7684\u8BA1\u7B97\u80FD\u529B\u3002</strong></p><p>\u5728\u8FDB\u7A0B\u6C60\u4E4B\u4E0A\uFF0C\u8FD8\u6709\u4E00\u4E2A\u201Cmaster\u201D\u8FDB\u7A0B\uFF0C\u4E13\u95E8\u7528\u6765\u7BA1\u7406\u8FDB\u7A0B\u6C60\u3002\u7528\u6765\u76D1\u63A7\u8FDB\u7A0B\uFF0C\u81EA\u52A8\u6062\u590D\u53D1\u751F\u5F02\u5E38\u7684 worker\uFF0C\u4FDD\u6301\u8FDB\u7A0B\u6C60\u7684\u7A33\u5B9A\u548C\u670D\u52A1\u80FD\u529B\u3002</p><p>master \u8FDB\u7A0B\u5B8C\u5168\u662F Nginx \u81EA\u884C\u7528 C \u8BED\u8A00\u5B9E\u73B0\u7684\uFF0C\u8FD9\u5C31\u6446\u8131\u4E86\u5916\u90E8\u7684\u4F9D\u8D56\uFF0C\u7B80\u5316\u4E86 Nginx \u7684\u90E8\u7F72\u548C\u914D\u7F6E\u3002</p><h2 id="i-o-\u591A\u8DEF\u590D\u7528" tabindex="-1"><a class="header-anchor" href="#i-o-\u591A\u8DEF\u590D\u7528" aria-hidden="true">#</a> I/O \u591A\u8DEF\u590D\u7528</h2><p>\u5982\u679C\u4F60\u7528 Java\u3001C \u7B49\u8BED\u8A00\u5199\u8FC7\u7A0B\u5E8F\uFF0C\u4E00\u5B9A\u5F88\u719F\u6089\u201C\u591A\u7EBF\u7A0B\u201D\u7684\u6982\u5FF5\uFF0C\u4F7F\u7528\u591A\u7EBF\u7A0B\u80FD\u591F\u5F88\u5BB9\u6613\u5B9E\u73B0\u5E76\u53D1\u5904\u7406\u3002\u4F46\u591A\u7EBF\u7A0B\u4E5F\u6709\u4E00\u4E9B\u7F3A\u70B9\uFF0C\u9664\u4E86\u521A\u624D\u8BF4\u5230\u7684\u201C\u4E0A\u4E0B\u6587\u5207\u6362\u201D\u6210\u672C\uFF0C\u8FD8\u6709\u7F16\u7A0B\u6A21\u578B\u590D\u6742\u3001\u6570\u636E\u7ADE\u4E89\u3001\u540C\u6B65\u7B49\u95EE\u9898\uFF0C\u5199\u51FA\u6B63\u786E\u3001\u5FEB\u901F\u7684\u591A\u7EBF\u7A0B\u7A0B\u5E8F\u5E76\u4E0D\u662F\u4E00\u4EF6\u5BB9\u6613\u7684\u4E8B\u60C5\u3002</p><blockquote><p>\u8FDB\u7A0B\u3001\u7EBF\u7A0B\u4E0A\u4E0B\u6587\u5207\u6362\u65F6\u7684\u6210\u672C\u7684\uFF0C\u4E3A\u4EC0\u4E48 Nginx \u8981\u5C3D\u91CF\u907F\u514D\uFF1F</p><p>\u5F53\u4ECE\u4E00\u4E2A\u4EFB\u52A1\u5207\u6362\u5230\u53E6\u4E00\u4E2A\u4EFB\u52A1\uFF0C\u5F53\u524D\u4EFB\u52A1\u7684\u4E0A\u4E0B\u6587\uFF0C\u5982\u5806\u6808\uFF0C\u6307\u4EE4\u6307\u9488\u7B49\u90FD\u8981\u4FDD\u5B58\u8D77\u6765\uFF0C\u4EE5\u4FBF\u4E0B\u6B21\u4EFB\u52A1\u65F6\u6062\u590D\uFF0C\u7136\u540E\u518D\u628A\u53E6\u4E00\u4E2A\u4EFB\u52A1\u7684\u5806\u6808\u52A0\u8F7D\u8FDB\u6765\uFF0C\u5982\u679C\u6709\u5927\u91CF\u7684\u4E0A\u4E0B\u6587\u5207\u6362\uFF0C\u5C31\u4F1A\u5F71\u54CD\u6027\u80FD\u3002</p></blockquote><p>\u6240\u4EE5 Nginx \u5C31\u9009\u62E9\u4E86\u5355\u7EBF\u7A0B\u7684\u65B9\u5F0F\uFF0C\u5E26\u6765\u7684\u597D\u5904\u5C31\u662F\u5F00\u53D1\u7B80\u5355\uFF0C\u6CA1\u6709\u4E92\u65A5\u9501\u7684\u6210\u672C\uFF0C\u51CF\u5C11\u7CFB\u7EDF\u6D88\u8017\u3002</p><p>\u8FD9\u8981\u5F52\u529F\u4E8E Nginx \u5229\u7528\u4E86 Linux \u5185\u6838\u91CC\u7684\u4E00\u4EF6\u201C\u795E\u5175\u5229\u5668\u201D<strong>\uFF0CI/O \u591A\u8DEF\u590D\u7528\u63A5\u53E3\uFF0C\u201C\u5927\u540D\u9F0E\u9F0E\u201D\u7684 epoll\u3002</strong></p><p><u>Web \u670D\u52A1\u5668\u4ECE\u6839\u672C\u4E0A\u6765\u8BF4\u662F\u201CI/O \u5BC6\u96C6\u578B\u201D\u800C\u4E0D\u662F\u201CCPU \u5BC6\u96C6\u578B\u201D\uFF0C\u5904\u7406\u80FD\u529B\u7684\u5173\u952E\u5728\u4E8E\u7F51\u7EDC\u6536\u53D1\u800C\u4E0D\u662F CPU \u8BA1\u7B97\uFF08\u8FD9\u91CC\u6682\u65F6\u4E0D\u8003\u8651 HTTPS \u7684\u52A0\u89E3\u5BC6\uFF09\uFF0C</u>\u800C\u7F51\u7EDC I/O \u4F1A\u56E0\u4E3A\u5404\u5F0F\u5404\u6837\u7684\u539F\u56E0\u4E0D\u5F97\u4E0D\u7B49\u5F85\uFF0C\u6BD4\u5982\u6570\u636E\u8FD8\u6CA1\u5230\u8FBE\u3001\u5BF9\u7AEF\u6CA1\u6709\u54CD\u5E94\u3001\u7F13\u51B2\u533A\u6EE1\u53D1\u4E0D\u51FA\u53BB\u7B49\u7B49\u3002</p><p>Nginx \u91CC\u4F7F\u7528\u7684 epoll\uFF0C\u5C31\u597D\u50CF\u662F HTTP/2 \u91CC\u7684\u201C\u591A\u8DEF\u590D\u7528\u201D\u6280\u672F\uFF0C\u5B83\u628A\u591A\u4E2A HTTP \u8BF7\u6C42\u5904\u7406\u6253\u6563\u6210\u788E\u7247\uFF0C\u90FD\u201C\u590D\u7528\u201D\u5230\u4E00\u4E2A\u5355\u7EBF\u7A0B\u91CC\uFF0C\u4E0D\u6309\u7167\u5148\u6765\u540E\u5230\u7684\u987A\u5E8F\u5904\u7406\uFF0C\u800C\u662F\u53EA\u5F53\u8FDE\u63A5\u4E0A\u771F\u6B63\u53EF\u8BFB\u3001\u53EF\u5199\u7684\u65F6\u5019\u624D\u5904\u7406\uFF0C\u5982\u679C\u53EF\u80FD\u53D1\u751F\u963B\u585E\u5C31\u7ACB\u523B\u5207\u6362\u51FA\u53BB\uFF0C\u5904\u7406\u5176\u4ED6\u7684\u8BF7\u6C42\u3002</p><p><strong>Nginx \u5C31\u5B8C\u5168\u6D88\u9664\u4E86 I/O \u963B\u585E\uFF0C\u628A CPU \u5229\u7528\u5F97\u201C\u6EE1\u6EE1\u5F53\u5F53\u201D\uFF0C\u53C8\u56E0\u4E3A\u7F51\u7EDC\u6536\u53D1\u5E76\u4E0D\u4F1A\u6D88\u8017\u592A\u591A CPU \u8BA1\u7B97\u80FD\u529B\uFF0C\u4E5F\u4E0D\u9700\u8981\u5207\u6362\u8FDB\u7A0B\u3001\u7EBF\u7A0B\uFF0C\u6240\u4EE5\u6574\u4F53\u7684 CPU \u8D1F\u8F7D\u662F\u76F8\u5F53\u4F4E\u7684\u3002</strong></p><p><img src="https://mc-web-1259409954.cos.ap-guangzhou.myqcloud.com/MyImages/202205142033336.png" alt="img"></p><p><u>epoll \u8FD8\u6709\u4E00\u4E2A\u7279\u70B9\uFF0C\u5927\u91CF\u7684\u8FDE\u63A5\u7BA1\u7406\u5DE5\u4F5C\u90FD\u662F\u5728\u64CD\u4F5C\u7CFB\u7EDF\u5185\u6838\u91CC\u505A\u7684\uFF0C\u8FD9\u5C31\u51CF\u8F7B\u4E86\u5E94\u7528\u7A0B\u5E8F\u7684\u8D1F\u62C5\uFF0C\u6240\u4EE5 Nginx \u53EF\u4EE5\u4E3A\u6BCF\u4E2A\u8FDE\u63A5\u53EA\u5206\u914D\u5F88\u5C0F\u7684\u5185\u5B58\u7EF4\u62A4\u72B6\u6001\uFF0C\u5373\u4F7F\u6709\u51E0\u4E07\u3001\u51E0\u5341\u4E07\u7684\u5E76\u53D1\u8FDE\u63A5\u4E5F\u53EA\u4F1A\u6D88\u8017\u51E0\u767E M \u5185\u5B58\uFF0C\u800C\u5176\u4ED6\u7684 Web \u670D\u52A1\u5668\u8FD9\u4E2A\u65F6\u5019\u65E9\u5C31\u201CMemory not enough\u201D\u4E86\u3002</u></p><h2 id="\u591A\u9636\u6BB5\u5904\u7406" tabindex="-1"><a class="header-anchor" href="#\u591A\u9636\u6BB5\u5904\u7406" aria-hidden="true">#</a> \u591A\u9636\u6BB5\u5904\u7406</h2><p>Nginx \u5728\u5185\u90E8\u4E5F\u91C7\u7528\u7684\u662F\u201C\u5316\u6574\u4E3A\u96F6\u201D\u7684\u601D\u8DEF\uFF0C\u628A\u6574\u4E2A Web \u670D\u52A1\u5668\u5206\u89E3\u6210\u4E86\u591A\u4E2A\u201C\u529F\u80FD\u6A21\u5757\u201D\uFF0C\u5C31\u597D\u50CF\u662F\u4E50\u9AD8\u79EF\u6728\uFF0C\u53EF\u4EE5\u5728\u914D\u7F6E\u6587\u4EF6\u91CC\u4EFB\u610F\u62FC\u63A5\u642D\u5EFA\uFF0C\u4ECE\u800C\u5B9E\u73B0\u4E86\u9AD8\u5EA6\u7684\u7075\u6D3B\u6027\u548C\u6269\u5C55\u6027\u3002</p><p>Nginx \u7684 HTTP \u5904\u7406\u6709\u56DB\u5927\u7C7B\u6A21\u5757\uFF1A</p><ul><li><p>handler \u6A21\u5757\uFF1A\u76F4\u63A5\u5904\u7406 HTTP \u8BF7\u6C42\uFF1B</p></li><li><p>filter \u6A21\u5757\uFF1A\u4E0D\u76F4\u63A5\u5904\u7406\u8BF7\u6C42\uFF0C\u800C\u662F\u52A0\u5DE5\u8FC7\u6EE4\u54CD\u5E94\u62A5\u6587\uFF1B</p></li><li><p>upstream \u6A21\u5757\uFF1A\u5B9E\u73B0\u53CD\u5411\u4EE3\u7406\u529F\u80FD\uFF0C\u8F6C\u53D1\u8BF7\u6C42\u5230\u5176\u4ED6\u670D\u52A1\u5668\uFF1B</p></li><li><p>balance \u6A21\u5757\uFF1A\u5B9E\u73B0\u53CD\u5411\u4EE3\u7406\u65F6\u7684\u8D1F\u8F7D\u5747\u8861\u7B97\u6CD5\u3002</p></li></ul><p>\u4E0D\u77E5\u9053\u4F60\u6709\u6CA1\u6709\u4E86\u89E3\u8FC7\u201C\u8BBE\u8BA1\u6A21\u5F0F\u201D\u8FD9\u65B9\u9762\u7684\u77E5\u8BC6\uFF0C\u5176\u4E2D\u6709\u4E00\u4E2A\u975E\u5E38\u6709\u7528\u7684\u6A21\u5F0F\u53EB\u505A\u201C\u804C\u8D23\u94FE\u201D\u3002\u5B83\u5C31\u597D\u50CF\u662F\u5DE5\u5382\u91CC\u7684\u6D41\u6C34\u7EBF\uFF0C\u539F\u6599\u4ECE\u4E00\u5934\u6D41\u5165\uFF0C\u7EBF\u4E0A\u6709\u8BB8\u591A\u5DE5\u4EBA\u4F1A\u8FDB\u884C\u5404\u79CD\u52A0\u5DE5\u5904\u7406\uFF0C\u6700\u540E\u4ECE\u53E6\u4E00\u5934\u51FA\u6765\u7684\u5C31\u662F\u5B8C\u6574\u7684\u4EA7\u54C1\u3002</p><p>Nginx \u91CC\u7684 handler \u6A21\u5757\u548C filter \u6A21\u5757\u5C31\u662F\u6309\u7167\u201C\u804C\u8D23\u94FE\u201D\u6A21\u5F0F\u8BBE\u8BA1\u548C\u7EC4\u7EC7\u7684\uFF0CHTTP \u8BF7\u6C42\u62A5\u6587\u5C31\u662F\u201C\u539F\u6750\u6599\u201D\uFF0C\u5404\u79CD\u6A21\u5757\u5C31\u662F\u5DE5\u5382\u91CC\u7684\u5DE5\u4EBA\uFF0C\u8D70\u5B8C\u6A21\u5757\u6784\u6210\u7684\u201C\u6D41\u6C34\u7EBF\u201D\uFF0C\u51FA\u6765\u7684\u5C31\u662F\u5904\u7406\u5B8C\u6210\u7684\u54CD\u5E94\u62A5\u6587\u3002</p><p><img src="https://mc-web-1259409954.cos.ap-guangzhou.myqcloud.com/MyImages/202205142042437.png" alt="img"></p><blockquote><p>Nginx \u7528\u8FDB\u7A0B\u3001epoll\u3001\u6A21\u5757\u6D41\u6C34\u7EBF\u5904\u7406 HTTP \u8BF7\u6C42\u7684\u8FC7\u7A0B\u3002</p><p>Nginx \u542F\u52A8\u8FDB\u7A0B\uFF0C\u4E00\u4E2Amaster\uFF0C\u591A\u4E2Aworker\uFF0C\u521B\u5EFAepoll\uFF0C\u76D1\u542C\u7AEF\u53E3\uFF0C\u591A\u8DEF\u590D\u7528\u6765\u7BA1\u7406http\u8BF7\u6C42\uFF0Chttp\u8BF7\u6C42\u5230\u8FBEworker\u5185\u90E8\uFF0C\u901A\u8FC7\u6A21\u5757\u6D41\u6C34\u7EBF\u5904\u7406\uFF0C\u6700\u540E\u8FD4\u56DEhttp\u54CD\u5E94\u3002</p></blockquote>',30);function a(r,o){return i}var h=e(n,[["render",a],["__file","Nginx.html.vue"]]);export{h as default};
